<?php // admin/blog-admin.php session_start(); $adminConfig = __DIR__. '/../admin.local.php'; if (file_exists($adminConfig)) { require_once $adminConfig; } function getConfigValue($key) { if (defined($key) && constant($key)!== '') { return constant($key); } $value = getenv($key); return ($value!== false && $value!== '')? $value: null; } function requireAdminAuth { $adminUser = getConfigValue('ADMIN_USER'); $adminPass = getConfigValue('ADMIN_PASS'); if (!$adminUser ||!$adminPass) { http_response_code(500); echo 'Admin credentials not configured.'; exit; } if (!empty($_SESSION['admin_authenticated']) && $_SESSION['admin_authenticated'] === true) { return; } $providedUser = $_SERVER['PHP_AUTH_USER']?? ''; $providedPass = $_SERVER['PHP_AUTH_PW']?? ''; if ($providedUser && $providedPass && hash_equals($adminUser, $providedUser) && hash_equals($adminPass, $providedPass)) { $_SESSION['admin_authenticated'] = true; return; } header('WWW-Authenticate: Basic realm="Broadsafe Admin"'); http_response_code(401); echo 'Authentication required.'; exit; } requireAdminAuth; if (empty($_SESSION['csrf_token'])) { $_SESSION['csrf_token'] = bin2hex(random_bytes(32)); } require_once '../database.php'; require_once '../blog-setup.php'; $database = new Database(); $conn = $database->getConnection(); ensureBlogTables($conn); ensureNewsletterTables($conn); $success = null; $error = null; function slugify($text) { $text = strtolower(trim($text)); $text = preg_replace('/[^a-z0-9]+/i', '-', $text); return trim($text, '-'); } function buildAuthorInitials($name) { $initials = ''; $parts = preg_split('/\s+/', trim($name)); foreach ($parts as $part) { if ($part!== '') { $initials.= strtoupper(substr($part, 0, 1)); } } return $initials; } function validateSlug(PDO $conn, $slug, $excludeId = null) { $sql = 'SELECT id FROM blog_posts WHERE slug =:slug'; $params = [':slug' => $slug]; if ($excludeId) { $sql.= ' AND id!=:id'; $params[':id'] = $excludeId; } $stmt = $conn->prepare($sql); $stmt->execute($params); return $stmt->fetch? false: true; } function sendNewsletterForPost(PDO $conn, array $post): bool { $stmt = $conn->prepare("SELECT email FROM newsletter_subscribers WHERE status = 'active'"); $stmt->execute; $subscribers = $stmt->fetchAll(PDO::FETCH_COLUMN); if (!$subscribers) { return true; } $scheme = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS']!== 'off')? 'https': 'http'; $host = $_SERVER['HTTP_HOST']?? 'localhost'; $baseUrl = $scheme. '://'. $host; $postUrl = $baseUrl. '/blog-post.php?slug='. urlencode($post['slug']); $subject = 'New Blog Post: '. $post['title']; $message = "Hello,\n\n"; $message.= "A new update has been posted on Broadsafe Services:\n\n"; $message.= $post['title']. "\n"; $message.= $post['excerpt']. "\n\n"; $message.= "Read more: ". $postUrl. "\n\n"; $message.= "Thank you for subscribing.\n"; $headers = "From: Broadsafe Services <info@broadsafeservices.com.au>\r\n"; $headers.= "Reply-To: info@broadsafeservices.com.au\r\n"; $headers.= "Content-Type: text/plain; charset=UTF-8\r\n"; foreach ($subscribers as $email) { @mail($email, $subject, $message, $headers); } return true; } if ($_SERVER['REQUEST_METHOD'] === 'POST') { if (empty($_POST['csrf_token']) ||!hash_equals($_SESSION['csrf_token'], $_POST['csrf_token'])) { $error = 'Invalid CSRF token.'; } else { $action = $_POST['action']?? ''; if ($action === 'delete') { $id = (int)($_POST['id']?? 0); if ($id <= 0) { $error = 'Invalid post ID.'; } else { $stmt = $conn->prepare('DELETE FROM blog_posts WHERE id =:id'); $stmt->execute([':id' => $id]); if ($stmt->rowCount === 0) { $error = 'Post not found.'; } else { updateBlogCategoryCounts($conn); $success = 'Post deleted.'; } } } if ($action === 'create' || $action === 'update') { $id = (int)($_POST['id']?? 0); $title = trim($_POST['title']?? ''); $excerpt = trim($_POST['excerpt']?? ''); $content = trim($_POST['content']?? ''); $category = trim($_POST['category']?? ''); $authorName = trim($_POST['author_name']?? ''); $authorTitle = trim($_POST['author_title']?? ''); $featuredImage = filter_var(trim($_POST['featured_image']?? ''), FILTER_SANITIZE_URL); $isFeatured = isset($_POST['is_featured'])? 1: 0; $status = trim($_POST['status']?? 'published'); $publishDate = trim($_POST['publish_date']?? ''); $metaDescription = trim($_POST['meta_description']?? ''); $metaKeywords = trim($_POST['meta_keywords']?? ''); $slugInput = trim($_POST['slug']?? ''); if ($title === '' || $excerpt === '' || $content === '' || $category === '' || $authorName === '') { $error = 'Please fill in all required fields.'; } else { $slug = $slugInput!== ''? slugify($slugInput): slugify($title); $authorInitials = buildAuthorInitials($authorName); $wordCount = str_word_count(strip_tags($content)); $readTime = max(1, (int)ceil($wordCount / 200)); $publishDateValue = $publishDate!== ''? $publishDate: date('Y-m-d H:i:s'); if (!validateSlug($conn, $slug, $action === 'update'? $id: null)) { $error = 'Slug already exists. Please use a different slug.'; } else { if ($action === 'create') { $stmt = $conn->prepare( 'INSERT INTO blog_posts (title, slug, excerpt, content, category, author_name, author_initials, author_title, featured_image, is_featured, read_time, meta_description, meta_keywords, publish_date, status) VALUES (:title,:slug,:excerpt,:content,:category,:author_name,:author_initials,:author_title,:featured_image,:is_featured,:read_time,:meta_description,:meta_keywords,:publish_date,:status)' ); $stmt->execute([ ':title' => $title, ':slug' => $slug, ':excerpt' => $excerpt, ':content' => $content, ':category' => $category, ':author_name' => $authorName, ':author_initials' => $authorInitials, ':author_title' => $authorTitle, ':featured_image' => $featuredImage, ':is_featured' => $isFeatured, ':read_time' => $readTime, ':meta_description' => $metaDescription, ':meta_keywords' => $metaKeywords, ':publish_date' => $publishDateValue, ':status' => $status ]); $newId = (int)$conn->lastInsertId; if ($isFeatured && $newId > 0) { $resetStmt = $conn->prepare('UPDATE blog_posts SET is_featured = 0 WHERE id!=:id'); $resetStmt->execute([':id' => $newId]); } if ($status === 'published' && $newId > 0) { $postStmt = $conn->prepare('SELECT * FROM blog_posts WHERE id =:id'); $postStmt->execute([':id' => $newId]); $postRow = $postStmt->fetch(); if ($postRow && (int)$postRow['newsletter_sent'] === 0) { if (sendNewsletterForPost($conn, $postRow)) { $conn->prepare('UPDATE blog_posts SET newsletter_sent = 1 WHERE id =:id')->execute([':id' => $newId]); } } } updateBlogCategoryCounts($conn); $success = 'Post created.'; } if ($action === 'update') { if ($id <= 0) { $error = 'Invalid post ID.'; } else { $stmt = $conn->prepare( 'UPDATE blog_posts SET title =:title, slug =:slug, excerpt =:excerpt, content =:content, category =:category, author_name =:author_name, author_initials =:author_initials, author_title =:author_title, featured_image =:featured_image, is_featured =:is_featured, read_time =:read_time, meta_description =:meta_description, meta_keywords =:meta_keywords, publish_date =:publish_date, status =:status, updated_at = NOW WHERE id =:id' ); $stmt->execute([ ':title' => $title, ':slug' => $slug, ':excerpt' => $excerpt, ':content' => $content, ':category' => $category, ':author_name' => $authorName, ':author_initials' => $authorInitials, ':author_title' => $authorTitle, ':featured_image' => $featuredImage, ':is_featured' => $isFeatured, ':read_time' => $readTime, ':meta_description' => $metaDescription, ':meta_keywords' => $metaKeywords, ':publish_date' => $publishDateValue, ':status' => $status, ':id' => $id ]); if ($isFeatured) { $resetStmt = $conn->prepare('UPDATE blog_posts SET is_featured = 0 WHERE id!=:id'); $resetStmt->execute([':id' => $id]); } if ($status === 'published') { $postStmt = $conn->prepare('SELECT * FROM blog_posts WHERE id =:id'); $postStmt->execute([':id' => $id]); $postRow = $postStmt->fetch(); if ($postRow && (int)$postRow['newsletter_sent'] === 0) { if (sendNewsletterForPost($conn, $postRow)) { $conn->prepare('UPDATE blog_posts SET newsletter_sent = 1 WHERE id =:id')->execute([':id' => $id]); } } } updateBlogCategoryCounts($conn); $success = 'Post updated.'; } } } } } } } $categoriesStmt = $conn->query('SELECT name, slug FROM blog_categories ORDER BY name'); $categories = $categoriesStmt->fetchAll(); $postsStmt = $conn->query('SELECT id, title, slug, status, publish_date, category FROM blog_posts ORDER BY publish_date DESC LIMIT 50'); $posts = $postsStmt->fetchAll(); $editId = isset($_GET['edit'])? (int)$_GET['edit']: 0; $editPost = null; if ($editId > 0) { $editStmt = $conn->prepare('SELECT * FROM blog_posts WHERE id =:id'); $editStmt->execute([':id' => $editId]); $editPost = $editStmt->fetch(); }?> <!DOCTYPE html>
